buildGradleAdditions.insert:

tasks.configureEach { task ->
	if (task.name == 'assembleDebug') {
		task.dependsOn ':tbStructArray_api:assembleDebug'
		task.dependsOn ':tbStructArray_impl:assembleDebug'
		task.dependsOn ':tbStructArray_android_service:assembleDebug'
		task.dependsOn ':tbStructArray_android_client:assembleDebug'
		task.dependsOn ':tbStructArray_android_messenger:assembleDebug'
	}
	if (task.name == 'assembleRelease') {
		task.dependsOn ':tbStructArray_api:assembleRelease'
		task.dependsOn ':tbStructArray_impl:assembleRelease'
		task.dependsOn ':tbStructArray_android_service:assembleRelease'
		task.dependsOn ':tbStructArray_android_client:assembleRelease'
		task.dependsOn ':tbStructArray_android_messenger:assembleRelease'
	}
}

proguardAdditions.insert:
-keep class tbStructArray.tbStructArrayjniservice.StructArrayFieldInterfaceJniService {
public *;
}
-keep class tbStructArray.tbStructArrayjniservice.StructArrayFieldInterfaceJniServiceStarter {
public *;
}
-keep class tbStructArray.tbStructArrayjniclient.StructArrayFieldInterfaceJniClient {
public *;
}
